INSERT INTO `message_templates` VALUES (1,'Initial Hearing Reminder','Dear {witness_name}, your case {case_no} is scheduled on {hearing_date} at {hearing_time}. Please attend on time.','Reminder: Dear {witness_name}, your case {case_no} will be heard on {hearing_date} at {hearing_time}. Kindly be present at the court.','{witness_name}, {hearing_date} তারিখে {court_name} এ {case_no} মামলায় আপনাকে সাক্ষী হিসেবে উপস্থিত থাকার জন্য অনুরোধ করা হলো।','সতর্কবার্তা: {witness_name}, আপনার মামলা {case_no} {hearing_date} তারিখে {hearing_time} সময়ে শুনানি হবে। আদালতে উপস্থিত থাকুন।','Subject: Court Hearing Notification – {case_no}\n\nDear {witness_name},\n\nYour case {case_no} is scheduled for hearing on {hearing_date} at {hearing_time}. Please be present at the court.\n\nThank you,\nCourt Administration','sms',1,1,'2025-10-03 05:57:36','2025-11-11 22:38:49');
/*!40000 ALTER TABLE `message_templates` ENABLE KEYS */;
